mapper.select:
SELECT * FROM ( SELECT t.*, ROW_NUMBER() OVER (ORDER BY t.sdate DESC, t.ymdhms DESC, t.barcode) AS rn FROM ( SELECT a.sdate, a.intf_yn, a.factory, a.storage, a.movefactory, a.movestorage, c.subname_ch AS car, a.itemcode, b.itemname, a.outqty, a.inqty, a.qty, a.loginid, a.ymdhms, a.ymdhms_f, a.barcode, SUBSTR(a.ymdhms, 9, 2) || ':' || SUBSTR(a.ymdhms, 11, 2) AS hhmm,
/* ✅ SENDING qty (같은 barcode 최신 1건) */ s.sending_qty,
/* ✅ 상태: qty 같으면 COMPLETE, 다르면 CHECKING */ CASE WHEN s.sending_qty IS NULL THEN 'CHECKING' WHEN NVL(a.qty, 0) = NVL(s.sending_qty, 0) THEN 'COMPLETE' ELSE 'CHECKING' END AS status FROM t_wms_factorymove a LEFT JOIN t_mi_item b ON b.itemcode = a.itemcode LEFT JOIN t_mi_typesub c ON c.subcode = b.carno AND c.typecode = 'MI041'
/* ✅ 같은 테이블에서 SENDING 최신 1건만 붙이기 */ LEFT JOIN ( SELECT barcode, qty AS sending_qty FROM ( SELECT barcode, qty, ROW_NUMBER() OVER (PARTITION BY barcode ORDER BY ymdhms DESC) AS rn FROM t_wms_factorymove WHERE useyn = 'Y' AND source = 'SENDING' ) WHERE rn = 1 ) s ON s.barcode = a.barcode
WHERE 1 = 1 AND a.useyn = 'Y' AND a.source = 'RECEIVING'
) t ) WHERE rn BETWEEN #{offset} + 1 AND #{offset} + #{itemsPerPage}

SELECT a.sdate, a.intf_yn, a.factory, a.storage, a.movefactory, a.movestorage, c.subname_ch AS car, a.itemcode, b.itemname, a.outqty, a.inqty, a.qty, a.loginid, a.ymdhms, a.ymdhms_f, a.barcode, SUBSTR(a.ymdhms, 9, 2) || ':' || SUBSTR(a.ymdhms, 11, 2) AS hhmm,
/* ✅ SENDING qty (같은 barcode 최신 1건) */ s.sending_qty,
/* ✅ 상태: qty 같으면 COMPLETE, 다르면 CHECKING */ CASE WHEN s.sending_qty IS NULL THEN 'CHECKING' WHEN NVL(a.qty, 0) = NVL(s.sending_qty, 0) THEN 'COMPLETE' ELSE 'CHECKING' END AS status FROM t_wms_factorymove a LEFT JOIN t_mi_item b ON b.itemcode = a.itemcode LEFT JOIN t_mi_typesub c ON c.subcode = b.carno AND c.typecode = 'MI041'
/* ✅ 같은 테이블에서 SENDING 최신 1건만 붙이기 */ LEFT JOIN ( SELECT barcode, qty AS sending_qty FROM ( SELECT barcode, qty, ROW_NUMBER() OVER (PARTITION BY barcode ORDER BY ymdhms DESC) AS rn FROM t_wms_factorymove WHERE useyn = 'Y' AND source = 'SENDING' ) WHERE rn = 1 ) s ON s.barcode = a.barcode
WHERE 1 = 1 AND a.useyn = 'Y' AND a.source = 'RECEIVING'
ORDER BY a.sdate DESC, a.ymdhms DESC, a.barcode

SELECT X.FACTORY, UPPER(X.STORAGE) AS STORAGE, X.CAR, X.ITEMCODE, X.SPEC, X.ITEMNAME,
SUM(X.CNT) AS countqty, SUM(X.NOSCANALL) - SUM(X.NOSCAN) AS INOUT, SUM(X.NOSCAN) AS noscanqty, SUM(X.NOSCANALL) AS noscanALLqty, SUM(X.ZERO_QTY) AS zeroqty, SUM(X.CNT) + SUM(X.NOSCANALL) AS totalqty, SUM(X.LOCATIONBACKUP) AS locationbackupqty, #{startdate} AS sdate FROM ( /* 1) REALSTOCK */ SELECT A.FACTORY, UPPER(A.STORAGE) AS STORAGE, C.SUBNAME_CH AS CAR, A.ITEMCODE, B.SPEC, B.ITEMNAME, SUM(A.QTY) AS CNT, 0 AS NOSCAN, 0 AS ZERO_QTY, 0 AS NOSCANALL, 0 AS LOCATIONBACKUP FROM ( SELECT DISTINCT FACTORY, STORAGE, ITEMCODE, BARCODE, QTY FROM T_WMS_REALSTOCK WHERE USEYN = 'Y'
) A LEFT JOIN T_MI_ITEM B ON A.ITEMCODE = B.ITEMCODE and B.deldate = ' ' LEFT JOIN T_MI_TYPESUB C ON B.CARNO = C.SUBCODE AND C.TYPECODE = 'MI041' GROUP BY A.FACTORY, A.STORAGE, C.SUBNAME_CH, A.ITEMCODE, B.SPEC, B.ITEMNAME
UNION ALL
/* 2) NOSCAN */ SELECT L.FACTORY, UPPER(L.STORAGE) AS STORAGE, C.SUBNAME_CH AS CAR, L.ITEMCODE, I.SPEC, I.ITEMNAME, 0 AS CNT, TO_NUMBER(L.QTY) AS NOSCAN, 0 AS ZERO_QTY, 0 AS NOSCANALL, 0 AS LOCATIONBACKUP FROM T_WMS_LOCATIONBACKUP L LEFT JOIN T_WMS_REALSTOCK R ON R.USEYN='Y' AND R.BARCODE=L.BARCODE AND R.SDATE=#{startdate} LEFT JOIN T_MI_ITEM I ON I.ITEMCODE=L.ITEMCODE and i.deldate = ' ' LEFT JOIN T_MI_TYPESUB C ON I.CARNO=C.SUBCODE AND C.TYPECODE='MI041' WHERE 1=1 AND L.USEYN='Y'
AND R.LOCATION IS NULL AND NOT EXISTS ( SELECT 1 FROM T_WMS_LOCATION LL WHERE LL.IID=L.IID AND LL.USEYN='N' AND UPPER(NVL(LL.MEMO_D,' ')) IN ('ADJUSTMENT','LOADEXCEPTION-NOSCAN') ) AND NOT ( NVL(( SELECT MAX(LL.USEYN) FROM T_WMS_LOCATION LL WHERE LL.BARCODE=L.BARCODE AND LL.USEYN='Y' ),'N')='N' OR NVL(( SELECT 'Y' FROM T_WMS_REALSTOCK RR WHERE RR.BARCODE=L.BARCODE AND RR.SDATE>=#{startdate} AND ROWNUM=1 ),'N')='Y' )
UNION ALL
/* 3) NOSCAN ALL */
SELECT L.FACTORY, UPPER(L.STORAGE) AS STORAGE, C.SUBNAME_CH AS CAR, L.ITEMCODE, I.SPEC, I.ITEMNAME, 0 AS CNT, 0 AS NOSCAN, 0 AS ZERO_QTY, TO_NUMBER(L.QTY) AS NOSCANALL, 0 AS LOCATIONBACKUP FROM T_WMS_LOCATIONBACKUP L LEFT JOIN T_WMS_REALSTOCK R ON R.USEYN='Y' AND R.BARCODE=L.BARCODE AND R.SDATE=#{startdate} LEFT JOIN T_MI_ITEM I ON I.ITEMCODE=L.ITEMCODE and i.deldate = ' ' LEFT JOIN T_MI_TYPESUB C ON I.CARNO=C.SUBCODE AND C.TYPECODE='MI041' WHERE 1=1 AND L.USEYN='Y'
AND R.LOCATION IS NULL
UNION ALL
/* 5) LOCATIONBACKUP QTY 260402 추가*/ SELECT L.FACTORY, UPPER(L.STORAGE) AS STORAGE, C.SUBNAME_CH AS CAR, L.ITEMCODE, I.SPEC, I.ITEMNAME, 0 AS CNT, 0 AS NOSCAN, 0 AS ZERO_QTY, 0 AS NOSCANALL, TO_NUMBER(L.QTY) AS LOCATIONBACKUP FROM T_WMS_LOCATIONBACKUP L LEFT JOIN T_MI_ITEM I ON I.ITEMCODE=L.ITEMCODE and i.deldate = ' ' LEFT JOIN T_MI_TYPESUB C ON I.CARNO=C.SUBCODE AND C.TYPECODE='MI041' WHERE 1=1 AND L.USEYN='Y'
UNION ALL /* 4) ZERO */ SELECT L.FACTORY, UPPER(L.STORAGE) AS STORAGE, C.SUBNAME_CH AS CAR, L.ITEMCODE, I.SPEC, I.ITEMNAME, 0 AS CNT, 0 AS NOSCAN, 0 AS ZERO_QTY, 0 AS NOSCANALL, 0 AS LOCATIONBACKUP FROM ( SELECT DISTINCT FACTORY, STORAGE, ITEMCODE FROM T_WMS_LOCATION WHERE 1 = 1
) L LEFT JOIN T_MI_ITEM I ON I.ITEMCODE=L.ITEMCODE and i.deldate = ' ' LEFT JOIN T_MI_TYPESUB C ON I.CARNO=C.SUBCODE AND C.TYPECODE='MI041'
) X WHERE 1=1
GROUP BY X.FACTORY, UPPER(X.STORAGE), X.CAR, X.ITEMCODE, X.SPEC, X.ITEMNAME ORDER BY X.ITEMCODE

SELECT FACTORY, CAR, ITEMCODE, SPEC, ITEMNAME, SUM(CNT) AS countqty, SUM(NOSCANALL)- SUM(NOSCAN) AS INOUT, SUM(NOSCAN) AS noscanqty, SUM(NOSCANALL) AS noscanALLqty, SUM(ZERO_QTY) AS zeroqty, SUM(cnt) + SUM(NOSCANALL) AS totalqty, #{startdate} as sdate
FROM ( ----------------------------------------------------------------- -- 1) 실재고 COUNT ----------------------------------------------------------------- SELECT A.FACTORY, C.SUBNAME_CH AS CAR, A.itemcode, B.SPEC, B.ITEMNAME, SUM(A.qty) AS CNT, 0 AS NOSCAN, 0 AS ZERO_QTY, 0 AS NOSCANALL FROM ( SELECT DISTINCT factory, itemcode, barcode, qty FROM T_WMS_REALSTOCK WHERE useyn = 'Y'
) A LEFT JOIN t_mi_item b ON a.itemcode = b.itemcode AND DELDATE = ' ' LEFT JOIN t_mi_typesub c ON b.carno = c.subcode AND c.typecode = 'MI041' GROUP BY A.factory, A.itemcode, B.SPEC, B.ITEMNAME, C.SUBNAME_CH
UNION ALL ----------------------------------------------------------------- -- 2) 미스캔 NOSCAN ----------------------------------------------------------------- SELECT l.factory, c.subname_ch AS car, l.itemcode, i.spec, i.itemname, 0 AS cnt, TO_NUMBER(l.qty) AS noscan, 0 AS zero_qty, 0 AS NOSCANALL FROM t_wms_locationbackup l LEFT JOIN t_wms_realstock r ON r.useyn = 'Y' AND r.barcode = l.barcode AND r.sdate = #{startdate}
LEFT JOIN t_mi_item i ON i.itemcode = l.itemcode AND DELDATE = ' ' LEFT JOIN t_mi_typesub c ON i.carno = c.subcode AND c.typecode = 'MI041' WHERE 1=1 AND L.USEYN = 'Y'
AND r.location IS NULL ---------------------------------------------------------------- -- ✅ 1. ADJUST / LOADEXCEPTION-NOSCAN 조정 건 제외 ---------------------------------------------------------------- AND NOT EXISTS ( SELECT 1 FROM t_wms_location ll WHERE ll.iid = l.iid AND ll.useyn = 'N' AND UPPER(NVL(ll.memo_d, ' ')) IN ('ADJUSTMENT', 'LOADEXCEPTION-NOSCAN') )
---------------------------------------------------------------- -- ✅ 2. NOSCAN 제외 조건 -- (1) 현재 바코드가 더 이상 사용중이 아닌 경우(useynbarcode = 'N') -- (2) 해당 바코드가 이후 실재고에서 다시 스캔된 경우(barcodescan = 'Y') ---------------------------------------------------------------- AND NOT ( --useynbarcode = 'N' 인 경우 NVL(( SELECT MAX(ll.useyn) FROM t_wms_location ll WHERE ll.barcode = l.barcode AND ll.useyn = 'Y' ), 'N') = 'N' OR --barcodescan = 'Y' 인 경우 (해당 날짜 이후에 실재고에 다시 스캔됨) NVL(( SELECT 'Y' FROM t_wms_realstock rr WHERE rr.barcode = l.barcode AND rr.sdate >= #{startdate} AND ROWNUM = 1 ), 'N') = 'Y' )
UNION ALL ----------------------------------------------------------------- -- 2) NOSCAN ALL ----------------------------------------------------------------- SELECT l.factory, c.subname_ch AS car, l.itemcode, i.spec, i.itemname, 0 AS cnt, 0 AS NOSCAN, 0 AS zero_qty, TO_NUMBER(l.qty) AS noscanALL FROM t_wms_locationbackup l LEFT JOIN t_wms_realstock r ON r.useyn = 'Y' AND r.barcode = l.barcode AND r.sdate = #{startdate}
LEFT JOIN t_mi_item i ON i.itemcode = l.itemcode AND DELDATE = ' ' LEFT JOIN t_mi_typesub c ON i.carno = c.subcode AND c.typecode = 'MI041' WHERE 1=1 AND L.USEYN = 'Y'
AND r.location IS NULL
UNION ALL ----------------------------------------------------------------- -- 3) ZERO 재고 : LOCATION 에는 있지만 총 qty = 0 OR REALSTOCK에도 없음 -----------------------------------------------------------------
SELECT L.factory, C.SUBNAME_CH AS CAR, L.itemcode, I.spec, I.itemname, 0 AS CNT, 0 AS NOSCAN, 0 AS ZERO_QTY, -- 단순 표시용 0 AS NOSCANALL FROM ( SELECT DISTINCT itemcode, factory FROM t_wms_location WHERE upper(factory) = #{factory}
AND UPPER(storage) IN ('MATERIAL', 'SIDE SEAT', 'OUTSIDE')
AND UPPER(storage) = UPPER(#{storage})
AND UPPER(storage) = UPPER('Material')
) L LEFT JOIN t_mi_item I ON I.itemcode = L.itemcode AND DELDATE = ' ' LEFT JOIN t_mi_typesub c ON I.carno = c.subcode AND c.typecode = 'MI041'
) where 1=1
GROUP BY FACTORY, CAR, ITEMCODE, SPEC, ITEMNAME ORDER BY ITEMCODE

