SELECT COUNT(*)
FROM V_ITEMHISTORY V
WHERE V.BARCODE = #{barcode}
  AND V.USEYN = 'Y'
  AND V.KIND NOT IN('STOCKCOUNT BARCODE', 'STOCKCOUNT LOCATION', 'LOCATION', 'LOCATION CHANGE')
  AND V.MKTIME > (
    SELECT MAX(MKTIME)
      FROM V_ITEMHISTORY 
     WHERE BARCODE = #{barcode}
       AND KIND = #{kind}

  )

