     , YMDHMS_D = TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
     , MEMO_D = 'PRODUCTMOVE_D'
     , LOGINID_D = #{loginid}
 WHERE USEYN = 'Y'  
   AND SDATE = #{date}
   AND KIND = 'PRODUCTMOVE'
   AND BARCODE = #{barcode}

UPDATE T_WMS_INSPECTION SET USEYN = 'N' , LOGINID_D = #{loginid} , MEMO_D = 'RETURN_D' , YMDHMS_D = TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS') WHERE IID IN
#{iid}
AND USEYN = 'Y'

UPDATE T_WMS_INSPECTION SET USEYN = 'N' , LOGINID_D = #{loginid} , MEMO_D = 'STORAGE_D' , YMDHMS_D = TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS') WHERE IID IN
#{iid}
AND USEYN = 'Y'

UPDATE T_WMS_CONDITIONCHANGE SET USEYN = 'N' , LOGINID_D = #{loginid} , MEMO_D = 'CHANGE_D' , YMDHMS_D = TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS') WHERE IID IN
#{iid}
AND USEYN = 'Y'

