SELECT * FROM ( SELECT t.*, ROW_NUMBER() OVER (ORDER BY t.itemcode) AS rn,
/* 전체 개수 */ ( SELECT COUNT(DISTINCT inner_t.barcode) FROM ( WITH ever_send AS ( SELECT DISTINCT barcode FROM t_wms_stockmove WHERE useyn='Y' AND source='SENDING' ), last_evt AS ( SELECT barcode, MAX(sdate) AS last_sdate FROM t_wms_stockmove WHERE useyn='Y' GROUP BY barcode ), last_src AS ( SELECT f.barcode, MAX(CASE WHEN f.sdate = l.last_sdate THEN f.source END) AS last_source FROM t_wms_stockmove f JOIN last_evt l ON l.barcode = f.barcode WHERE f.useyn='Y' GROUP BY f.barcode ) SELECT a.barcode FROM t_wms_stockmove a LEFT JOIN t_mi_item b ON b.itemcode = a.itemcode LEFT JOIN t_mi_typesub c ON c.subcode = b.carno AND c.typecode = 'MI041' LEFT JOIN ever_send es ON es.barcode = a.barcode LEFT JOIN last_src ls ON ls.barcode = a.barcode WHERE a.useyn = 'Y'
GROUP BY a.itemcode, b.itemname, c.subname_ch, a.barcode ) inner_t ) AS TOTALCOUNT,
/* 총 수량 */ ( SELECT NVL(SUM(inner_t.total_qty), 0) FROM ( WITH ever_send AS ( SELECT DISTINCT barcode FROM t_wms_stockmove WHERE useyn='Y' AND source='SENDING' ), last_evt AS ( SELECT barcode, MAX(sdate) AS last_sdate FROM t_wms_stockmove WHERE useyn='Y' GROUP BY barcode ), last_src AS ( SELECT f.barcode, MAX(CASE WHEN f.sdate = l.last_sdate THEN f.source END) AS last_source FROM t_wms_stockmove f JOIN last_evt l ON l.barcode = f.barcode WHERE f.useyn='Y' GROUP BY f.barcode ) SELECT SUM(CASE WHEN source = 'SENDING' THEN qty END) + SUM(CASE WHEN source = 'RECEIVING' THEN qty END) AS total_qty FROM t_wms_stockmove a LEFT JOIN t_mi_item b ON b.itemcode = a.itemcode LEFT JOIN t_mi_typesub c ON c.subcode = b.carno AND c.typecode = 'MI041' LEFT JOIN ever_send es ON es.barcode = a.barcode LEFT JOIN last_src ls ON ls.barcode = a.barcode WHERE a.useyn = 'Y'
GROUP BY a.itemcode, b.itemname, c.subname_ch, a.barcode ) inner_t ) AS TOTALQTY FROM ( WITH ever_send AS ( SELECT DISTINCT barcode FROM t_wms_stockmove WHERE useyn='Y' AND source='SENDING' ), last_evt AS ( SELECT barcode, MAX(sdate) AS last_sdate FROM t_wms_stockmove WHERE useyn='Y' GROUP BY barcode ), last_src AS ( SELECT f.barcode, MAX(CASE WHEN f.sdate = l.last_sdate THEN f.source END) AS last_source FROM t_wms_stockmove f JOIN last_evt l ON l.barcode = f.barcode WHERE f.useyn='Y' GROUP BY f.barcode ) SELECT MAX(CASE WHEN source = 'SENDING' THEN sdate END) AS FROMDATE, MAX(CASE WHEN source = 'RECEIVING' THEN sdate END) AS TODATE, c.SUBNAME_CH as car, a.itemcode, b.spec as oitemcode, b.itemname, a.barcode, SUM(CASE WHEN source = 'SENDING' THEN qty END) AS FROMQTY, SUM(CASE WHEN source = 'RECEIVING' THEN qty END) AS TOQTY, MAX(CASE WHEN source = 'SENDING' THEN factory END) AS FROMFACTORY, MAX(CASE WHEN source = 'SENDING' THEN storage1 END) AS FROMSTORAGE, MAX(CASE WHEN source = 'RECEIVING' THEN factory END) AS TOFACTORY, MAX(CASE WHEN source = 'RECEIVING' THEN storage2 END) AS TOSTORAGE, CASE WHEN SUM(CASE WHEN a.source='RECEIVING' THEN 1 END) = 0 THEN NULL WHEN MAX( CASE WHEN a.source='RECEIVING' AND es.barcode IS NOT NULL AND ls.last_source = 'RECEIVING' THEN 1 ELSE 0 END ) = 1 THEN 'O' ELSE 'X' END AS COMPLETE FROM t_wms_stockmove a LEFT JOIN t_mi_item b ON b.itemcode = a.itemcode AND b.deldate = ' ' LEFT JOIN t_mi_typesub c ON c.subcode = b.carno AND c.typecode = 'MI041' LEFT JOIN ever_send es ON es.barcode = a.barcode LEFT JOIN last_src ls ON ls.barcode = a.barcode WHERE a.useyn = 'Y'
GROUP BY a.itemcode, b.spec, b.itemname, c.subname_ch, a.barcode ) t ) where complete = 'O'
and rn BETWEEN #{offset} + 1 AND #{offset} + #{limit}
AND fromdate IS NULL
AND fromdate IS NOT NULL
ORDER BY rn

SELECT * FROM ( SELECT t.*, ROW_NUMBER() OVER (ORDER BY t.sdate DESC, t.ymdhms DESC, t.barcode) AS rn FROM ( SELECT a.sdate, a.intf_yn, a.factory, a.storage1, a.storage2, c.subname_ch AS car, a.itemcode, b.spec as oitemcode, b.itemname, a.qty, a.loginid, a.ymdhms, a.barcode, SUBSTR(a.ymdhms, 9, 2) || ':' || SUBSTR(a.ymdhms, 11, 2) AS hhmm,
/* ✅ SENDING qty (같은 barcode 최신 1건) */ s.sending_qty,
/* ✅ 상태: qty 같으면 COMPLETE, 다르면 CHECKING */ CASE WHEN s.sending_qty IS NULL THEN 'CHECKING' WHEN NVL(a.qty, 0) = NVL(s.sending_qty, 0) THEN 'COMPLETE' ELSE 'CHECKING' END AS status FROM t_wms_stockmove a LEFT JOIN t_mi_item b ON b.itemcode = a.itemcode AND deldate = ' ' LEFT JOIN t_mi_typesub c ON c.subcode = b.carno AND c.typecode = 'MI041'
/* ✅ 같은 테이블에서 SENDING 최신 1건만 붙이기 */ LEFT JOIN ( SELECT barcode, qty AS sending_qty FROM ( SELECT barcode, qty, ROW_NUMBER() OVER (PARTITION BY barcode ORDER BY ymdhms DESC) AS rn FROM t_wms_stockmove WHERE useyn = 'Y' AND source = 'SENDING' ) WHERE rn = 1 ) s ON s.barcode = a.barcode WHERE 1 = 1 AND a.useyn = 'Y' AND a.source = 'RECEIVING'
) t ) WHERE rn BETWEEN #{offset} + 1 AND #{offset} + #{itemsPerPage}

SELECT a.sdate, a.intf_yn, a.factory, a.storage1, a.storage2, c.subname_ch AS car, a.itemcode, b.spec as oitemcode, b.itemname, a.qty, a.loginid, a.ymdhms, a.barcode, SUBSTR(a.ymdhms, 9, 2) || ':' || SUBSTR(a.ymdhms, 11, 2) AS hhmm,
/* ✅ SENDING qty (같은 barcode 최신 1건) */ s.sending_qty,
/* ✅ 상태: qty 같으면 COMPLETE, 다르면 CHECKING */ CASE WHEN s.sending_qty IS NULL THEN 'CHECKING' WHEN NVL(a.qty, 0) = NVL(s.sending_qty, 0) THEN 'COMPLETE' ELSE 'CHECKING' END AS status FROM t_wms_stockmove a LEFT JOIN t_mi_item b ON b.itemcode = a.itemcode AND deldate = ' ' LEFT JOIN t_mi_typesub c ON c.subcode = b.carno AND c.typecode = 'MI041'
/* ✅ 같은 테이블에서 SENDING 최신 1건만 붙이기 */ LEFT JOIN ( SELECT barcode, qty AS sending_qty FROM ( SELECT barcode, qty, ROW_NUMBER() OVER (PARTITION BY barcode ORDER BY ymdhms DESC) AS rn FROM t_wms_stockmove WHERE useyn = 'Y' AND source = 'SENDING' ) WHERE rn = 1 ) s ON s.barcode = a.barcode WHERE 1 = 1 AND a.useyn = 'Y' AND a.source = 'RECEIVING'

