UPDATE T_WMS_LOCATION
SET USEYN = 'N',
	YMDHMS_D = #{ymdhms},
	MEMO_D = 'MOVE WAREHOUSE'
WHERE BARCODE = #{barcode}
AND FACTORY = #{factory}
AND STORAGE = #{storage1}
AND USEYN = 'Y'

UPDATE T_WMS_OUTBOUND@MEXLINK
SET COMPLETE_YN = 'Y'
WHERE INVOICENO = #{invoice_no}
AND OUTDATE = #{date}
AND COMPLETE_YN = 'N'

UPDATE T_WMS_OUTBOUND@MEXLINK
SET COMPLETE_YN = 'N'
WHERE INVOICENO = #{invoice_no}
AND OUTDATE = #{date}
AND COMPLETE_YN = 'Y'
